+        exec: failureExec as unknown as Parameters<typeof loadShellEnvFallback>[0]["exec"],
+        logger: { warn: vi.fn() },
+      }),
+    ).toMatchObject({
+      ok: false,
+      applied: [],
+      error: "boom",
+    });
